-- SQLite-compatible SQL file representing schema and sample data for sql_agent_ex2
-- Note: This file contains SQL DDL/DML. To create a binary SQLite database, run these statements
-- using the sqlite3 CLI: sqlite3 sql_agent_ex2.db < sql_agent_ex2.db

PRAGMA foreign_keys = ON;

CREATE TABLE users (
  user_id INTEGER PRIMARY KEY,
  username TEXT NOT NULL UNIQUE,
  email TEXT UNIQUE
);

CREATE TABLE products (
  product_id INTEGER PRIMARY KEY,
  name TEXT NOT NULL,
  price REAL NOT NULL CHECK(price >= 0),
  stock INTEGER NOT NULL DEFAULT 0
);

CREATE TABLE purchases (
  purchase_id INTEGER PRIMARY KEY,
  user_id INTEGER NOT NULL,
  purchase_time TEXT NOT NULL,
  FOREIGN KEY(user_id) REFERENCES users(user_id)
);

CREATE TABLE purchase_items (
  item_id INTEGER PRIMARY KEY,
  purchase_id INTEGER NOT NULL,
  product_id INTEGER NOT NULL,
  unit_price REAL NOT NULL,
  quantity INTEGER NOT NULL CHECK(quantity > 0),
  FOREIGN KEY(purchase_id) REFERENCES purchases(purchase_id),
  FOREIGN KEY(product_id) REFERENCES products(product_id)
);

CREATE TABLE tags (
  tag_id INTEGER PRIMARY KEY,
  name TEXT UNIQUE NOT NULL
);

CREATE TABLE product_tags (
  product_id INTEGER NOT NULL,
  tag_id INTEGER NOT NULL,
  PRIMARY KEY(product_id, tag_id),
  FOREIGN KEY(product_id) REFERENCES products(product_id),
  FOREIGN KEY(tag_id) REFERENCES tags(tag_id)
);

CREATE INDEX idx_purchase_items_product_id ON purchase_items(product_id);

-- Trigger: before inserting a purchase_item, ensure sufficient stock and decrement stock
CREATE TRIGGER trg_purchase_items_before_insert
BEFORE INSERT ON purchase_items
FOR EACH ROW
BEGIN
  -- If not enough stock, abort
  SELECT CASE
    WHEN (SELECT stock FROM products WHERE product_id = NEW.product_id) - NEW.quantity < 0
    THEN RAISE(ABORT, 'out of stock')
    ELSE (UPDATE products SET stock = stock - NEW.quantity WHERE product_id = NEW.product_id)
  END;
END;

